var getAclAddress = async (publicClient) => {
  const ACL_IFACE = "function acl() view returns (address)";
  const aclAbi = parseAbi([ACL_IFACE]);
  return await publicClient.readContract({
    address: TASK_MANAGER_ADDRESS,
    abi: aclAbi,
    functionName: "acl"
  });
};
